#include <stdio.h>
#include <stdlib.h>

// Structure for an interval
typedef struct Interval {
    int start;
    int end;
} Interval;

// Function to compare two intervals based on start time
int compareIntervals(const void *a, const void *b) {
    Interval *intervalA = (Interval *)a;
    Interval *intervalB = (Interval *)b;
    return intervalA->start - intervalB->start;
}

// Function to merge overlapping intervals
Interval* mergeIntervals(Interval *intervals, int intervalsSize, int *returnSize) {
    // Sort intervals based on start time
    qsort(intervals, intervalsSize, sizeof(Interval), compareIntervals);

    // Initialize result array
    Interval *result = (Interval *)malloc(intervalsSize * sizeof(Interval));
    *returnSize = 0;

    // Loop through each interval
    int i = 0;
    while (i < intervalsSize) {
        // Start of current merged interval
        int start = intervals[i].start;
        int end = intervals[i].end;

        // Merge with all overlapping intervals
        int j = i + 1;
        while (j < intervalsSize && intervals[j].start <= end) {
            // Update end to the maximum of current end and overlapping interval's end
            end = (end > intervals[j].end) ? end : intervals[j].end;
            j++;
        }

        // Add the merged interval to result
        result[(*returnSize)++] = (Interval){start, end};

        // Move to the next non-overlapping interval
        i = j;
    }

    return result;
}

int main() {
    Interval intervals[] = {{1, 3}, {2, 6}, {8, 10}, {15, 18}};
    int intervalsSize = sizeof(intervals) / sizeof(intervals[0]);
    int returnSize;
    Interval *result = mergeIntervals(intervals, intervalsSize, &returnSize);

    for (int i = 0; i < returnSize; i++) {
        printf("[%d, %d] ", result[i].start, result[i].end);
    }
    return 0;
}

